import 'package:flutter/material.dart';
import 'package:uni_links/uni_links.dart';

void main() {
  runApp(MyApp());
}

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      initialRoute: '/',
      onGenerateRoute: (settings) {
        switch (settings.name) {
          case '/':
            return MaterialPageRoute(builder: (_) => HomeScreen());
          case '/profile':
            var id = settings.arguments as String;
            return MaterialPageRoute(builder: (_) => ProfileScreen(id: id));
          case '/payment/confirm':
            return MaterialPageRoute(builder: (_) => PaymentConfirmScreen());
          default:
            throw Exception('Invalid route: ${settings.name}');
        }
      },
    );
  }
}

class HomeScreen extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    listenForLinks(context);
    return Scaffold(
      appBar: AppBar(title: Text('Home')),
      body: Center(child: Text('Welcome to the Home Screen')),
    );
  }

  void listenForLinks(BuildContext context) async {
    try {
      Uri? link = await getInitialLink();
      if (link != null) {
        handleLink(context, link);
      }
    } on FormatException {}

    linkHandler() async {
      Uri? link = await getLinkStream().receiveFirst();
      if (link != null) {
        handleLink(context, link);
      }
    }

    WidgetsBinding.instance.addPostFrameCallback((_) => linkHandler());
  }

  void handleLink(BuildContext context, Uri link) {
    switch (link.path) {
      case '/profile':
        var id = link.queryParameters['id'];
        Navigator.of(context).pushNamed('/profile', arguments: id);
        break;
      case '/payment/confirm':
        Navigator.of(context).pushNamed('/payment/confirm');
        break;
      default:
        print('Unknown deep link: $link');
    }
  }
}

